    </div>
  </div>

  <!-- 12. 里程碑 -->
  <div class="section" id="sec12">
    <div class="section-header">
      <span class="section-number">12</span>
      <h2>里程碑</h2>
    </div>
    <div class="milestone-timeline">
      <div class="milestone-item">
        <span class="tag-phase phase-m0">M0 · MVP · 第 8 周</span>
        <h4>内测可用</h4>
        <ul>
          <li>单 Agent + Team（≤5 人）跑通</li>
          <li>节点图视图</li>
          <li>MCP Server 可用（暴露给 Claude Code）</li>
          <li>5 个团队模板</li>
          <li>邀请制内测，目标 20 个早期用户</li>
        </ul>
      </div>
      <div class="milestone-item">
