import "dotenv/config";
import express from "express";
import { exec } from "node:child_process";
import { promises as fs } from "node:fs";
import path from "node:path";
import { promisify } from "node:util";

const execAsync = promisify(exec);
const app = express();
const port = Number(process.env.PORT ?? 8787);

// ─── Types ───────────────────────────────────────────────────────────────────

type Role = "system" | "user" | "assistant" | "tool";

type ToolCall = {
 id: string;
 type: "function";
 function: { name: string; arguments: string };
};

type ChatMessage = {
 role: Role;
 content: string | null;
 tool_calls?: ToolCall[];
 tool_call_id?: string;
 name?: string;
};

type ToolDefinition = {
 type: "function";
 function: {
 name: string;
 description: string;
 parameters: Record ;
 };
};

type ToolResult = {
 tool_call_id: string;
 content: string;
 isError?: boolean;
};

type ApiConfig = {
 baseUrl?: string;
 apiKey?: string;
 model?: string;
};

type Message = {
 id: string;
 role: Exclude ;
 content: string;
 tool_calls?: ToolCall[];
 createdAt: string;
};

type ToolMessage = {
 id: string;
 role: "tool";
 content: string;
 tool_call_id: string;
 toolName: string;
 createdAt: string;
};

type StoredMessage = Message | ToolMessage;

type Conversation = {
 id: string;
 projectId: string;
 title: string;
 shortcut?: string;
 updatedAt: string;
 messages: StoredMessage[];
};

type Project = {
 id: string;
 name: string;
 conversations: string[];
};

type Skill = {
 id: string;
 title: string;
 description: string;
 accent: string;
 connected: boolean;
 installed: boolean;
 npmPackage?: string;
};

type Automation = {
 id: string;
 title: string;
 schedule: string;
 enabled: boolean;
 createdAt: string;
};

type ChatCompletionResponse = {
 id?: string;
 model?: string;
 choices?: Array ;
 usage?: unknown;
 error?: { message?: string };
};

type PersistedStore = {
 projects: Project[];
 conversations: Conversation[];
 skills: Skill[];
 automations: Automation[];
};

// ─── Constants ───────────────────────────────────────────────────────────────

